function StructInvasionBoss:CreateByPb(pb)
    self.refId = pb.refId
    self.endTime = pb.endTime
    self.rank = pb.rank
    self.hurt = pb.hurt
    self.alreadyDareCount = pb.alreadyDareCount
    self.allHurt = pb.allHurt
    self.nextRefresh = pb.nextRefresh
    self.lastHurt = tonumber(pb.lastHurt)


